/**
 * TicketSeam API Service Integration
 * HTTP client for TicketSeam API Gateway endpoints
 */

export class TicketSeamAWS {
  constructor() {
    this.apiUrl = process.env.REACT_APP_API_URL || 'https://1ylbl5fjqc.execute-api.us-east-1.amazonaws.com/dev';
    this.headers = {
      'Content-Type': 'application/json',
      'Accept': 'application/json'
    };
  }

  /**
   * Make HTTP request to API Gateway
   */
  async makeRequest(endpoint, method = 'GET', data = null) {
    try {
      const url = `${this.apiUrl}${endpoint}`;
      const options = {
        method,
        headers: this.headers,
        mode: 'cors'
      };

      if (data && (method === 'POST' || method === 'PUT')) {
        options.body = JSON.stringify(data);
      }

      const response = await fetch(url, options);
      
      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      return await response.json();
    } catch (error) {
      console.error(`Error making ${method} request to ${endpoint}:`, error);
      throw error;
    }
  }

  // ==================== EVENT OPERATIONS ====================

  /**
   * Create a new event
   */
  async createEvent(eventData) {
    try {
      return await this.makeRequest('/events', 'POST', eventData);
    } catch (error) {
      console.error('Error creating event:', error);
      throw error;
    }
  }

  /**
   * Update an existing event
   */
  async updateEvent(eventId, eventData) {
    try {
      return await this.makeRequest(`/events/${eventId}`, 'PUT', eventData);
    } catch (error) {
      console.error('Error updating event:', error);
      throw error;
    }
  }

  /**
   * Get event details
   */
  async getEventDetails(eventId) {
    try {
      return await this.makeRequest(`/events/${eventId}`, 'GET');
    } catch (error) {
      console.error('Error getting event details:', error);
      throw error;
    }
  }

  /**
   * List events for an organizer
   */
  async listEvents(organizerId, filters = {}) {
    try {
      const queryParams = new URLSearchParams({ organizerId, ...filters });
      return await this.makeRequest(`/events?${queryParams}`, 'GET');
    } catch (error) {
      console.error('Error listing events:', error);
      throw error;
    }
  }

  // ==================== TICKET OPERATIONS ====================

  /**
   * Generate tickets for a purchase
   */
  async generateTickets(ticketData) {
    try {
      return await this.makeRequest('/tickets/generate', 'POST', ticketData);
    } catch (error) {
      console.error('Error generating tickets:', error);
      throw error;
    }
  }

  /**
   * Validate a ticket at entry
   */
  async validateTicket(validationData) {
    try {
      return await this.makeRequest('/tickets/validate', 'POST', validationData);
    } catch (error) {
      console.error('Error validating ticket:', error);
      throw error;
    }
  }

  /**
   * Get ticket details
   */
  async getTicketDetails(ticketId) {
    try {
      return await this.makeRequest(`/tickets/${ticketId}`, 'GET');
    } catch (error) {
      console.error('Error getting ticket details:', error);
      throw error;
    }
  }

  // ==================== PAYMENT OPERATIONS ====================

  /**
   * Process payment for tickets
   */
  async processPayment(paymentData) {
    try {
      return await this.makeRequest('/payments/process', 'POST', paymentData);
    } catch (error) {
      console.error('Error processing payment:', error);
      throw error;
    }
  }

  /**
   * Get purchase details
   */
  async getPurchaseDetails(purchaseId) {
    try {
      return await this.makeRequest(`/purchases/${purchaseId}`, 'GET');
    } catch (error) {
      console.error('Error getting purchase details:', error);
      throw error;
    }
  }

  // ==================== ANALYTICS OPERATIONS ====================

  /**
   * Get event analytics
   */
  async getEventAnalytics(eventId) {
    try {
      return await this.makeRequest(`/analytics/reports?eventId=${eventId}`, 'GET');
    } catch (error) {
      console.error('Error getting event analytics:', error);
      throw error;
    }
  }

  /**
   * Get validation analytics
   */
  async getValidationAnalytics(eventId) {
    try {
      return await this.makeRequest(`/analytics/scans?eventId=${eventId}`, 'GET');
    } catch (error) {
      console.error('Error getting validation analytics:', error);
      throw error;
    }
  }

  // ==================== EMAIL OPERATIONS ====================

  /**
   * Send ticket email
   */
  async sendTicketEmail(emailData) {
    try {
      return await this.makeRequest('/email/send-tickets', 'POST', emailData);
    } catch (error) {
      console.error('Error sending ticket email:', error);
      throw error;
    }
  }

  /**
   * Send custom email
   */
  async sendEmail(to, subject, htmlContent, textContent = null) {
    try {
      const emailData = {
        to: Array.isArray(to) ? to : [to],
        subject,
        htmlContent,
        textContent
      };
      return await this.makeRequest('/email/send', 'POST', emailData);
    } catch (error) {
      console.error('Error sending email:', error);
      throw error;
    }
  }

  // ==================== FILE OPERATIONS ====================

  /**
   * Upload file (via API)
   */
  async uploadFile(file, path) {
    try {
      const formData = new FormData();
      formData.append('file', file);
      formData.append('path', path);

      const response = await fetch(`${this.apiUrl}/files/upload`, {
        method: 'POST',
        body: formData
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      return await response.json();
    } catch (error) {
      console.error('Error uploading file:', error);
      throw error;
    }
  }

  /**
   * Get file URL
   */
  async getFileUrl(filePath) {
    try {
      return await this.makeRequest(`/files/url?path=${encodeURIComponent(filePath)}`, 'GET');
    } catch (error) {
      console.error('Error getting file URL:', error);
      throw error;
    }
  }

  // ==================== DATA OPERATIONS ====================

  /**
   * Query data (via API)
   */
  async queryData(tableName, queryParams) {
    try {
      const params = new URLSearchParams({ table: tableName, ...queryParams });
      return await this.makeRequest(`/data/query?${params}`, 'GET');
    } catch (error) {
      console.error('Error querying data:', error);
      throw error;
    }
  }

  /**
   * Get data item
   */
  async getDataItem(tableName, key) {
    try {
      return await this.makeRequest(`/data/${tableName}/${key}`, 'GET');
    } catch (error) {
      console.error('Error getting data item:', error);
      throw error;
    }
  }

  // ==================== NOTIFICATION OPERATIONS ====================

  /**
   * Send SMS notification
   */
  async sendSMS(phoneNumber, message) {
    try {
      return await this.makeRequest('/notifications/sms', 'POST', {
        phoneNumber,
        message
      });
    } catch (error) {
      console.error('Error sending SMS:', error);
      throw error;
    }
  }

  /**
   * Send push notification
   */
  async sendPushNotification(endpointArn, message, subject = null) {
    try {
      return await this.makeRequest('/notifications/push', 'POST', {
        endpointArn,
        message,
        subject
      });
    } catch (error) {
      console.error('Error sending push notification:', error);
      throw error;
    }
  }

  // ==================== UTILITY METHODS ====================

  /**
   * Generate unique ID
   */
  generateId(prefix = '') {
    const timestamp = Date.now().toString(36);
    const random = Math.random().toString(36).substr(2, 5);
    return `${prefix}${timestamp}${random}`;
  }

  /**
   * Format currency
   */
  formatCurrency(amount, currency = 'USD') {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: currency
    }).format(amount);
  }

  /**
   * Format date
   */
  formatDate(date, options = {}) {
    const defaultOptions = {
      year: 'numeric',
      month: 'long',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    };

    return new Intl.DateTimeFormat('en-US', {
      ...defaultOptions,
      ...options
    }).format(new Date(date));
  }

  /**
   * Validate email format
   */
  isValidEmail(email) {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  }

  /**
   * Validate phone number format
   */
  isValidPhone(phone) {
    const phoneRegex = /^\+?[\d\s\-()]+$/;
    return phoneRegex.test(phone) && phone.replace(/\D/g, '').length >= 10;
  }
}

// Export singleton instance
export const ticketSeamAWS = new TicketSeamAWS();
export default TicketSeamAWS;
