import React, { useState } from 'react';
import EventCreator from './components/EventCreator';
import TicketTypes from './components/TicketTypes';
import EventDashboard from './components/EventDashboard';
import QRTicketGenerator from './components/QRTicketGenerator';
import './styles/App.css';

function App() {
  const [currentView, setCurrentView] = useState('dashboard');
  const [selectedEvent, setSelectedEvent] = useState(null);

  const renderCurrentView = () => {
    switch (currentView) {
      case 'create-event':
        return (
          <EventCreator
            onEventCreated={(event) => {
              setSelectedEvent(event);
              setCurrentView('dashboard');
            }}
            onCancel={() => setCurrentView('dashboard')}
          />
        );
      case 'ticket-types':
        return (
          <TicketTypes
            eventId={selectedEvent?.eventId}
            ticketTypes={selectedEvent?.ticketTypes || []}
            onUpdate={(index, updatedType) => {
              // Handle ticket type update
              console.log('Update ticket type:', index, updatedType);
            }}
            onAdd={(newType) => {
              // Handle adding new ticket type
              console.log('Add ticket type:', newType);
            }}
            onRemove={(index) => {
              // Handle removing ticket type
              console.log('Remove ticket type:', index);
            }}
            onReorder={(fromIndex, toIndex) => {
              // Handle reordering ticket types
              console.log('Reorder ticket types:', fromIndex, toIndex);
            }}
          />
        );
      case 'qr-generator':
        return (
          <QRTicketGenerator
            eventId={selectedEvent?.eventId}
            ticketData={[]} // This would come from actual ticket data
            onGenerated={(tickets) => {
              console.log('Generated tickets:', tickets);
            }}
          />
        );
      default:
        return (
          <EventDashboard
            eventId={selectedEvent?.eventId}
            eventData={selectedEvent}
          />
        );
    }
  };

  return (
    <div className="App">
      <header className="App-header">
        <div className="header-content">
          <h1>TicketSeam</h1>
          <p>Seamless ticketing for seamless events</p>
        </div>
        <nav className="App-nav">
          <button
            className={currentView === 'dashboard' ? 'active' : ''}
            onClick={() => setCurrentView('dashboard')}
          >
            Dashboard
          </button>
          <button
            className={currentView === 'create-event' ? 'active' : ''}
            onClick={() => setCurrentView('create-event')}
          >
            Create Event
          </button>
          <button
            className={currentView === 'ticket-types' ? 'active' : ''}
            onClick={() => setCurrentView('ticket-types')}
          >
            Ticket Types
          </button>
          <button
            className={currentView === 'qr-generator' ? 'active' : ''}
            onClick={() => setCurrentView('qr-generator')}
          >
            QR Generator
          </button>
        </nav>
      </header>

      <main className="App-main">
        {renderCurrentView()}
      </main>

      <footer className="App-footer">
        <p>&copy; 2024 TicketSeam. All rights reserved.</p>
      </footer>
    </div>
  );
}

export default App;
