// Helper functions
export const getConfig = (path) => {
  return path.split('.').reduce((obj, key) => obj?.[key], TICKETING_CONFIG);
};

export const isFeatureEnabled = (feature) => {
  return TICKETING_CONFIG.features[feature] || false;
};

export const getEnvironmentConfig = () => {
  const env = process.env.NODE_ENV || 'development';
  return TICKETING_CONFIG.environment[env] || TICKETING_CONFIG.environment.development;
};

export const calculateFees = (subtotal) => {
  const { platformFee, processingFee, flatFee, minimumFee, maximumFee } = TICKETING_CONFIG.feeStructure;
  
  const platformFeeAmount = subtotal * platformFee;
  const processingFeeAmount = subtotal * processingFee;
  const totalFees = platformFeeAmount + processingFeeAmount + flatFee;
  
  // Apply minimum and maximum fee limits
  const finalFees = Math.max(minimumFee, Math.min(maximumFee, totalFees));
  
  return {
    platformFee: Math.round(platformFeeAmount * 100) / 100,
    processingFee: Math.round(processingFeeAmount * 100) / 100,
    flatFee: flatFee,
    total: Math.round(finalFees * 100) / 100
  };
};

export const formatCurrency = (amount, currency = 'USD') => {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: currency
  }).format(amount);
};

export const formatDate = (date, options = {}) => {
  const defaultOptions = {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit'
  };

  return new Intl.DateTimeFormat('en-US', {
    ...defaultOptions,
    ...options
  }).format(new Date(date));
};

export const validateEmail = (email) => {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email);
};

export const validatePhone = (phone) => {
  const phoneRegex = /^\+?[\d\s\-()]+$/;
  return phoneRegex.test(phone) && phone.replace(/\D/g, '').length >= 10;
};

export const generateTicketId = () => {
  const timestamp = Date.now().toString(36);
  const random = Math.random().toString(36).substr(2, 5);
  return `tkt_${timestamp}${random}`;
};

export const generateEventId = () => {
  const timestamp = Date.now().toString(36);
  const random = Math.random().toString(36).substr(2, 5);
  return `evt_${timestamp}${random}`;
};

export const generatePurchaseId = () => {
  const timestamp = Date.now().toString(36);
  const random = Math.random().toString(36).substr(2, 5);
  return `pur_${timestamp}${random}`;
};

