/**
 * TicketSeam EventDashboard Component
 * Real-time sales analytics and event management dashboard
 */

import React, { useState, useEffect } from 'react';
import { ticketSeamAWS } from '../services/aws-service';
import { formatCurrency, formatDate } from '../config/ticketing';
import './EventDashboard.css';

const EventDashboard = ({ eventId, eventData }) => {
  const [analytics, setAnalytics] = useState(null);
  const [salesData, setSalesData] = useState([]);
  const [validationData, setValidationData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [timeRange, setTimeRange] = useState('24h');
  const [refreshInterval, setRefreshInterval] = useState(30000); // 30 seconds

  const loadDashboardData = async () => {
    try {
      setLoading(true);
      
      // For now, create mock data since the API endpoints may not be fully implemented
      const mockAnalytics = {
        totalRevenue: 12500.00,
        totalTicketsSold: 150,
        totalCapacity: 200,
        conversionRate: 12.5,
        averageOrderValue: 83.33,
        ticketTypeSales: {
          'tt_general': { name: 'General Admission', sold: 100, available: 150, revenue: 7500.00 },
          'tt_vip': { name: 'VIP Package', sold: 50, available: 50, revenue: 5000.00 }
        },
        hourlySales: [
          { timestamp: '2024-01-15T10:00:00Z', sales: 5 },
          { timestamp: '2024-01-15T11:00:00Z', sales: 12 },
          { timestamp: '2024-01-15T12:00:00Z', sales: 8 },
          { timestamp: '2024-01-15T13:00:00Z', sales: 15 },
          { timestamp: '2024-01-15T14:00:00Z', sales: 22 }
        ]
      };

      const mockValidationData = {
        totalScans: 45,
        validEntries: 42,
        invalidEntries: 2,
        duplicateEntries: 1
      };

      setAnalytics(mockAnalytics);
      setValidationData(mockValidationData);

      // Load recent sales data
      await loadSalesData();
    } catch (err) {
      console.error('Error loading dashboard data:', err);
      setError('Failed to load dashboard data');
    } finally {
      setLoading(false);
    }
  };

  const loadSalesData = async () => {
    try {
      // Mock sales data for now
      const mockSalesData = [
        {
          purchaseId: 'pur_1234567890',
          customerName: 'John Doe',
          timestamp: '2024-01-15T14:30:00Z',
          tickets: [{ typeName: 'General Admission', quantity: 2 }],
          pricing: { total: 150.00 },
          paymentStatus: 'completed'
        },
        {
          purchaseId: 'pur_0987654321',
          customerName: 'Jane Smith',
          timestamp: '2024-01-15T13:45:00Z',
          tickets: [{ typeName: 'VIP Package', quantity: 1 }],
          pricing: { total: 200.00 },
          paymentStatus: 'completed'
        },
        {
          purchaseId: 'pur_1122334455',
          customerName: 'Bob Johnson',
          timestamp: '2024-01-15T12:15:00Z',
          tickets: [{ typeName: 'General Admission', quantity: 4 }],
          pricing: { total: 300.00 },
          paymentStatus: 'completed'
        }
      ];

      setSalesData(mockSalesData);
    } catch (err) {
      console.error('Error loading sales data:', err);
    }
  };

  useEffect(() => {
    loadDashboardData();
    
    // Set up auto-refresh
    const interval = setInterval(loadDashboardData, refreshInterval);
    return () => clearInterval(interval);
  }, [eventId, timeRange, refreshInterval]);

  // const getTimeRangeLabel = (range) => {
  //   const ranges = {
  //     '1h': 'Last Hour',
  //     '24h': 'Last 24 Hours',
  //     '7d': 'Last 7 Days',
  //     '30d': 'Last 30 Days',
  //     'all': 'All Time'
  //   };
  //   return ranges[range] || range;
  // };

  const calculateConversionRate = () => {
    if (!analytics) return 0;
    const totalVisitors = analytics.totalVisitors || 0;
    const totalTicketsSold = analytics.totalTicketsSold || 0;
    return totalVisitors > 0 ? (totalTicketsSold / totalVisitors * 100).toFixed(1) : 0;
  };

  const calculateAverageOrderValue = () => {
    if (!analytics) return 0;
    const totalRevenue = analytics.totalRevenue || 0;
    const totalOrders = analytics.totalOrders || 0;
    return totalOrders > 0 ? totalRevenue / totalOrders : 0;
  };

  const getTicketTypeSales = () => {
    if (!analytics || !analytics.ticketTypeSales) return [];
    return Object.entries(analytics.ticketTypeSales).map(([typeId, data]) => ({
      typeId,
      ...data
    }));
  };

  const getHourlySales = () => {
    if (!analytics || !analytics.hourlySales) return [];
    return analytics.hourlySales.map(hour => ({
      ...hour,
      time: new Date(hour.timestamp).toLocaleTimeString('en-US', {
        hour: '2-digit',
        minute: '2-digit'
      })
    }));
  };

  const renderMetricCard = (title, value, subtitle, trend = null) => (
    <div className="metric-card">
      <div className="metric-header">
        <h3>{title}</h3>
        {trend && (
          <span className={`trend ${trend > 0 ? 'positive' : 'negative'}`}>
            {trend > 0 ? '+' : ''}{trend}%
          </span>
        )}
      </div>
      <div className="metric-value">{value}</div>
      {subtitle && <div className="metric-subtitle">{subtitle}</div>}
    </div>
  );

  const renderSalesChart = () => {
    const hourlyData = getHourlySales();
    if (hourlyData.length === 0) return null;

    const maxSales = Math.max(...hourlyData.map(h => h.sales));
    
    return (
      <div className="chart-container">
        <h4>Sales Over Time</h4>
        <div className="sales-chart">
          {hourlyData.map((hour, index) => (
            <div key={index} className="chart-bar">
              <div
                className="bar"
                style={{
                  height: `${(hour.sales / maxSales) * 100}%`
                }}
              />
              <div className="bar-label">{hour.time}</div>
              <div className="bar-value">{hour.sales}</div>
            </div>
          ))}
        </div>
      </div>
    );
  };

  const renderTicketTypeBreakdown = () => {
    const ticketTypes = getTicketTypeSales();
    if (ticketTypes.length === 0) return null;

    return (
      <div className="ticket-type-breakdown">
        <h4>Ticket Type Sales</h4>
        <div className="breakdown-list">
          {ticketTypes.map((type) => (
            <div key={type.typeId} className="breakdown-item">
              <div className="breakdown-info">
                <span className="type-name">{type.name}</span>
                <span className="type-sold">{type.sold} sold</span>
              </div>
              <div className="breakdown-progress">
                <div
                  className="progress-bar"
                  style={{
                    width: `${(type.sold / type.available) * 100}%`
                  }}
                />
              </div>
              <div className="breakdown-stats">
                <span>{type.sold} / {type.available}</span>
                <span>{formatCurrency(type.revenue)}</span>
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  };

  const renderRecentSales = () => (
    <div className="recent-sales">
      <h4>Recent Sales</h4>
      <div className="sales-list">
        {salesData.slice(0, 10).map((sale) => (
          <div key={sale.purchaseId} className="sale-item">
            <div className="sale-info">
              <span className="customer-name">{sale.customerName}</span>
              <span className="sale-time">
                {formatDate(sale.timestamp, { 
                  hour: '2-digit', 
                  minute: '2-digit' 
                })}
              </span>
            </div>
            <div className="sale-details">
              <span className="ticket-count">{sale.tickets.length} tickets</span>
              <span className="sale-amount">{formatCurrency(sale.pricing.total)}</span>
            </div>
            <div className={`sale-status ${sale.paymentStatus}`}>
              {sale.paymentStatus}
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  const renderValidationStats = () => {
    if (!validationData) return null;

    return (
      <div className="validation-stats">
        <h4>Entry Statistics</h4>
        <div className="validation-metrics">
          <div className="validation-metric">
            <span className="metric-label">Total Scans:</span>
            <span className="metric-value">{validationData.totalScans}</span>
          </div>
          <div className="validation-metric">
            <span className="metric-label">Valid Entries:</span>
            <span className="metric-value">{validationData.validEntries}</span>
          </div>
          <div className="validation-metric">
            <span className="metric-label">Invalid Entries:</span>
            <span className="metric-value">{validationData.invalidEntries}</span>
          </div>
          <div className="validation-metric">
            <span className="metric-label">Duplicate Entries:</span>
            <span className="metric-value">{validationData.duplicateEntries}</span>
          </div>
        </div>
      </div>
    );
  };

  if (loading && !analytics) {
    return (
      <div className="event-dashboard loading">
        <div className="loading-spinner">Loading dashboard...</div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="event-dashboard error">
        <div className="error-message">{error}</div>
        <button onClick={loadDashboardData} className="btn-primary">
          Retry
        </button>
      </div>
    );
  }

  return (
    <div className="event-dashboard">
      <div className="dashboard-header">
        <h2>{eventData?.name || 'Event Dashboard'}</h2>
        <div className="dashboard-controls">
          <select
            value={timeRange}
            onChange={(e) => setTimeRange(e.target.value)}
            className="time-range-selector"
          >
            <option value="1h">Last Hour</option>
            <option value="24h">Last 24 Hours</option>
            <option value="7d">Last 7 Days</option>
            <option value="30d">Last 30 Days</option>
            <option value="all">All Time</option>
          </select>
          <button
            onClick={loadDashboardData}
            className="refresh-button"
            disabled={loading}
          >
            {loading ? 'Refreshing...' : 'Refresh'}
          </button>
        </div>
      </div>

      <div className="dashboard-metrics">
        {renderMetricCard(
          'Total Revenue',
          formatCurrency(analytics?.totalRevenue || 0),
          'From ticket sales',
          analytics?.revenueTrend
        )}
        {renderMetricCard(
          'Tickets Sold',
          (analytics?.totalTicketsSold || 0).toLocaleString(),
          `of ${(analytics?.totalCapacity || 0).toLocaleString()} available`,
          analytics?.ticketsTrend
        )}
        {renderMetricCard(
          'Conversion Rate',
          `${calculateConversionRate()}%`,
          'Visitors to buyers',
          analytics?.conversionTrend
        )}
        {renderMetricCard(
          'Avg Order Value',
          formatCurrency(calculateAverageOrderValue()),
          'Per transaction',
          analytics?.aovTrend
        )}
      </div>

      <div className="dashboard-content">
        <div className="dashboard-left">
          {renderSalesChart()}
          {renderTicketTypeBreakdown()}
        </div>
        
        <div className="dashboard-right">
          {renderRecentSales()}
          {renderValidationStats()}
        </div>
      </div>

      <div className="dashboard-footer">
        <div className="last-updated">
          Last updated: {new Date().toLocaleTimeString()}
        </div>
        <div className="auto-refresh">
          <label>
            <input
              type="checkbox"
              checked={refreshInterval > 0}
              onChange={(e) => setRefreshInterval(e.target.checked ? 30000 : 0)}
            />
            Auto-refresh every 30 seconds
          </label>
        </div>
      </div>
    </div>
  );
};

export default EventDashboard;
