/**
 * TicketSeam QRTicketGenerator Component
 * Generate QR codes for tickets and handle ticket delivery
 */

import React, { useState, useEffect } from 'react';
import QRCode from 'qrcode';
import { ticketSeamAWS } from '../services/aws-service';
import { formatCurrency, formatDate } from '../config/ticketing';
import './QRTicketGenerator.css';

const QRTicketGenerator = ({ eventId, ticketData, onGenerated }) => {
  const [qrCodes, setQrCodes] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [selectedTickets, setSelectedTickets] = useState([]);
  const [emailData, setEmailData] = useState({
    to: '',
    subject: '',
    message: ''
  });
  const [showEmailForm, setShowEmailForm] = useState(false);
  // const canvasRef = useRef(null);

  const generateQRCodes = async () => {
    setLoading(true);
    setError(null);

    try {
      const generatedCodes = await Promise.all(
        ticketData.map(async (ticket) => {
          const qrData = {
            ticketId: ticket.ticketId,
            eventId: ticket.eventId,
            typeId: ticket.typeId,
            purchaseId: ticket.purchaseId,
            attendeeEmail: ticket.attendeeEmail,
            timestamp: new Date().toISOString(),
            checksum: generateChecksum(ticket.ticketId, ticket.eventId, ticket.attendeeEmail),
            version: '1.0'
          };

          const qrCodeUrl = await QRCode.toDataURL(JSON.stringify(qrData), {
            width: 300,
            margin: 2,
            color: {
              dark: '#000000',
              light: '#FFFFFF'
            },
            errorCorrectionLevel: 'M'
          });

          return {
            ...ticket,
            qrCodeData: qrData,
            qrCodeUrl,
            qrCodeText: JSON.stringify(qrData)
          };
        })
      );

      setQrCodes(generatedCodes);
      onGenerated?.(generatedCodes);
    } catch (err) {
      console.error('Error generating QR codes:', err);
      setError('Failed to generate QR codes');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (ticketData && ticketData.length > 0) {
      generateQRCodes();
    }
  }, [ticketData]);

  const generateChecksum = (ticketId, eventId, attendeeEmail) => {
    const data = `${ticketId}-${eventId}-${attendeeEmail}`;
    // Simple checksum - in production, use proper crypto
    return btoa(data).substring(0, 20);
  };

  const handleTicketSelect = (ticketId, selected) => {
    if (selected) {
      setSelectedTickets(prev => [...prev, ticketId]);
    } else {
      setSelectedTickets(prev => prev.filter(id => id !== ticketId));
    }
  };

  const handleSelectAll = () => {
    if (selectedTickets.length === qrCodes.length) {
      setSelectedTickets([]);
    } else {
      setSelectedTickets(qrCodes.map(ticket => ticket.ticketId));
    }
  };

  const downloadQRCode = (ticket) => {
    const link = document.createElement('a');
    link.download = `ticket-${ticket.ticketId}.png`;
    link.href = ticket.qrCodeUrl;
    link.click();
  };

  const downloadAllSelected = () => {
    selectedTickets.forEach(ticketId => {
      const ticket = qrCodes.find(t => t.ticketId === ticketId);
      if (ticket) {
        downloadQRCode(ticket);
      }
    });
  };

  const downloadTicketPDF = async (ticket) => {
    try {
      setLoading(true);
      
      // Generate PDF with ticket information
      const pdfData = await generateTicketPDF(ticket);
      
      const blob = new Blob([pdfData], { type: 'application/pdf' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `ticket-${ticket.ticketId}.pdf`;
      link.click();
      URL.revokeObjectURL(url);
    } catch (err) {
      console.error('Error generating PDF:', err);
      setError('Failed to generate PDF');
    } finally {
      setLoading(false);
    }
  };

  const generateTicketPDF = async (ticket) => {
    // This would integrate with a PDF generation library like jsPDF
    // For now, return a simple HTML representation
    const html = `
      <!DOCTYPE html>
      <html>
      <head>
        <title>Ticket - ${ticket.ticketId}</title>
        <style>
          body { font-family: Arial, sans-serif; margin: 20px; }
          .ticket { border: 2px solid #000; padding: 20px; max-width: 400px; }
          .header { text-align: center; margin-bottom: 20px; }
          .qr-code { text-align: center; margin: 20px 0; }
          .ticket-info { margin: 10px 0; }
          .ticket-info strong { display: inline-block; width: 120px; }
        </style>
      </head>
      <body>
        <div class="ticket">
          <div class="header">
            <h1>TicketSeam Ticket</h1>
            <h2>${ticket.eventName}</h2>
          </div>
          <div class="qr-code">
            <img src="${ticket.qrCodeUrl}" alt="QR Code" width="200" />
          </div>
          <div class="ticket-info">
            <strong>Ticket ID:</strong> ${ticket.ticketId}<br>
            <strong>Attendee:</strong> ${ticket.attendeeName}<br>
            <strong>Email:</strong> ${ticket.attendeeEmail}<br>
            <strong>Type:</strong> ${ticket.typeName}<br>
            <strong>Price:</strong> ${formatCurrency(ticket.price)}<br>
            <strong>Date:</strong> ${formatDate(ticket.eventDate)}<br>
            <strong>Time:</strong> ${ticket.startTime}<br>
            <strong>Location:</strong> ${ticket.location}
          </div>
        </div>
      </body>
      </html>
    `;
    
    return html;
  };

  const sendTicketsEmail = async () => {
    try {
      setLoading(true);
      
      const selectedTicketsData = qrCodes.filter(ticket => 
        selectedTickets.includes(ticket.ticketId)
      );

      await ticketSeamAWS.sendTicketEmail({
        to: emailData.to,
        subject: emailData.subject,
        tickets: selectedTicketsData,
        eventData: ticketData[0] // Assuming all tickets are for the same event
      });

      setShowEmailForm(false);
      setEmailData({ to: '', subject: '', message: '' });
    } catch (err) {
      console.error('Error sending email:', err);
      setError('Failed to send email');
    } finally {
      setLoading(false);
    }
  };

  const renderTicketCard = (ticket) => (
    <div key={ticket.ticketId} className="ticket-card">
      <div className="ticket-header">
        <div className="ticket-checkbox">
          <input
            type="checkbox"
            checked={selectedTickets.includes(ticket.ticketId)}
            onChange={(e) => handleTicketSelect(ticket.ticketId, e.target.checked)}
          />
        </div>
        <div className="ticket-info">
          <h4>{ticket.attendeeName}</h4>
          <p className="ticket-email">{ticket.attendeeEmail}</p>
          <p className="ticket-type">{ticket.typeName}</p>
        </div>
        <div className="ticket-price">
          {formatCurrency(ticket.price)}
        </div>
      </div>

      <div className="qr-code-section">
        <div className="qr-code-container">
          <img src={ticket.qrCodeUrl} alt="QR Code" className="qr-code-image" />
        </div>
        <div className="qr-code-actions">
          <button
            onClick={() => downloadQRCode(ticket)}
            className="btn-secondary"
          >
            Download QR
          </button>
          <button
            onClick={() => downloadTicketPDF(ticket)}
            className="btn-secondary"
          >
            Download PDF
          </button>
        </div>
      </div>

      <div className="ticket-details">
        <div className="detail-row">
          <span className="detail-label">Ticket ID:</span>
          <span className="detail-value">{ticket.ticketId}</span>
        </div>
        <div className="detail-row">
          <span className="detail-label">Event:</span>
          <span className="detail-value">{ticket.eventName}</span>
        </div>
        <div className="detail-row">
          <span className="detail-label">Date:</span>
          <span className="detail-value">{formatDate(ticket.eventDate)}</span>
        </div>
        <div className="detail-row">
          <span className="detail-label">Time:</span>
          <span className="detail-value">{ticket.startTime}</span>
        </div>
        <div className="detail-row">
          <span className="detail-label">Location:</span>
          <span className="detail-value">{ticket.location}</span>
        </div>
      </div>

      <div className="ticket-actions">
        <button
          onClick={() => navigator.clipboard.writeText(ticket.qrCodeText)}
          className="btn-outline"
        >
          Copy QR Data
        </button>
        <button
          onClick={() => window.print()}
          className="btn-outline"
        >
          Print Ticket
        </button>
      </div>
    </div>
  );

  const renderEmailForm = () => (
    <div className="email-form-overlay">
      <div className="email-form">
        <h3>Send Tickets via Email</h3>
        
        <div className="form-group">
          <label htmlFor="emailTo">To:</label>
          <input
            type="email"
            id="emailTo"
            value={emailData.to}
            onChange={(e) => setEmailData(prev => ({ ...prev, to: e.target.value }))}
            placeholder="recipient@example.com"
            required
          />
        </div>

        <div className="form-group">
          <label htmlFor="emailSubject">Subject:</label>
          <input
            type="text"
            id="emailSubject"
            value={emailData.subject}
            onChange={(e) => setEmailData(prev => ({ ...prev, subject: e.target.value }))}
            placeholder="Your tickets for [Event Name]"
            required
          />
        </div>

        <div className="form-group">
          <label htmlFor="emailMessage">Message:</label>
          <textarea
            id="emailMessage"
            value={emailData.message}
            onChange={(e) => setEmailData(prev => ({ ...prev, message: e.target.value }))}
            rows="4"
            placeholder="Optional message to include with the tickets..."
          />
        </div>

        <div className="form-actions">
          <button
            onClick={sendTicketsEmail}
            className="btn-primary"
            disabled={loading || !emailData.to || !emailData.subject}
          >
            {loading ? 'Sending...' : 'Send Tickets'}
          </button>
          <button
            onClick={() => setShowEmailForm(false)}
            className="btn-secondary"
          >
            Cancel
          </button>
        </div>
      </div>
    </div>
  );

  if (loading && qrCodes.length === 0) {
    return (
      <div className="qr-ticket-generator loading">
        <div className="loading-spinner">Generating QR codes...</div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="qr-ticket-generator error">
        <div className="error-message">{error}</div>
        <button onClick={generateQRCodes} className="btn-primary">
          Retry
        </button>
      </div>
    );
  }

  return (
    <div className="qr-ticket-generator">
      <div className="generator-header">
        <h2>QR Ticket Generator</h2>
        <div className="generator-actions">
          <button
            onClick={handleSelectAll}
            className="btn-outline"
          >
            {selectedTickets.length === qrCodes.length ? 'Deselect All' : 'Select All'}
          </button>
          <button
            onClick={downloadAllSelected}
            className="btn-secondary"
            disabled={selectedTickets.length === 0}
          >
            Download Selected ({selectedTickets.length})
          </button>
          <button
            onClick={() => setShowEmailForm(true)}
            className="btn-primary"
            disabled={selectedTickets.length === 0}
          >
            Email Selected ({selectedTickets.length})
          </button>
        </div>
      </div>

      <div className="tickets-grid">
        {qrCodes.map(renderTicketCard)}
      </div>

      {showEmailForm && renderEmailForm()}
    </div>
  );
};

export default QRTicketGenerator;
